#include <bits/stdc++.h>
using namespace std;
const int N=15,M=1<<12,mod=100000000;
long long dp[N][M],n,m,a[N][N],cnt[N];
vector<int> v;
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            cin>>a[i][j];
            if(a[i][j]) cnt[i]+=(1<<(m-j));
        }
    }
    for(int i=0;i<(1<<m);i++)
    {
        if(((i&(i>>1))==0)&&((i&(i<<1))==0))
        {
            v.push_back(i);
            if((i&cnt[1])==i) dp[1][i]=1;
        }
    }
    for(int i=2;i<=n;i++)
    {
        for(int j=0;j<v.size();j++)
        {
            int x=v[j];
            if((x&cnt[i-1])!=x) continue;
            for(int k=0;k<v.size();k++)
            {
                int x2=v[k];
                if((x2&cnt[i])!=x2) continue;
                if(x&x2) continue;
                dp[i][x2]=(dp[i][x2]+dp[i-1][x])%mod;
            }
        }
    }
    long ans=0;
    for(int i=0;i<v.size();i++)
    {
        int x=v[i];
        ans=(ans+dp[n][x])%mod;
    }
    cout<<ans;
    return 0;
}
